import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.Lq6hU67C.js";const u=JSON.parse('{"title":"Scene survival heuristic","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/scene-survival-heuristic.md","filePath":"how-to/scene-survival-heuristic.md"}'),o={name:"how-to/scene-survival-heuristic.md"};function r(n,e,d,l,c,h){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="scene-survival-heuristic" tabindex="-1">Scene survival heuristic <a class="header-anchor" href="#scene-survival-heuristic" aria-label="Permalink to &quot;Scene survival heuristic&quot;">​</a></h1><p><strong>SceneSurvivor</strong> is the highest-confidence automated heuristic in Addressables Leak Detector.</p><h2 id="rule" tabindex="-1">Rule <a class="header-anchor" href="#rule" aria-label="Permalink to &quot;Rule&quot;">​</a></h2><p>If a live Addressables handle <strong>survives a non-additive scene load</strong> without an intervening Release, severity escalates to <strong>SceneSurvivor</strong> (red).</p><h2 id="why-it-matters" tabindex="-1">Why it matters <a class="header-anchor" href="#why-it-matters" aria-label="Permalink to &quot;Why it matters&quot;">​</a></h2><p>Non-additive scene changes destroy most scene objects but <strong>do not</strong> automatically release Addressables handles your code still holds. This is a common source of silent memory growth across level transitions.</p><h2 id="additive-vs-non-additive" tabindex="-1">Additive vs non-additive <a class="header-anchor" href="#additive-vs-non-additive" aria-label="Permalink to &quot;Additive vs non-additive&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scene load mode</th><th>SceneSurvivor triggered?</th></tr></thead><tbody><tr><td><code>LoadSceneMode.Single</code></td><td>Yes — prior scene unloaded</td></tr><tr><td><code>LoadSceneMode.Additive</code></td><td>No — demo scene may stay loaded</td></tr></tbody></table><p>The demo <strong>Leak + Scene B (Additive)</strong> button illustrates a live handle that stays grey/yellow, not red.</p><h2 id="expected-demo-behavior" tabindex="-1">Expected demo behavior <a class="header-anchor" href="#expected-demo-behavior" aria-label="Permalink to &quot;Expected demo behavior&quot;">​</a></h2><ol><li><strong>Leak + Scene B (Single)</strong> — load asset, transition to Scene B without Release → red after return or on observation during transition.</li><li><strong>Release + Scene B</strong> — Release before transition → no live entry.</li></ol><h2 id="false-positives" tabindex="-1">False positives <a class="header-anchor" href="#false-positives" aria-label="Permalink to &quot;False positives&quot;">​</a></h2><p>Legitimate DontDestroyOnLoad services that hold handles across scenes may trigger SceneSurvivor. Use <code>[AddressablesIntentionallyPersistent]</code> or allowlist if intentional.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./demo-scene.html">Demo scene</a></li><li><a href="./../concepts/leak-definition-and-severity.html">Leak definition and severity</a></li></ul>',15)])])}const m=t(o,[["render",r]]);export{u as __pageData,m as default};
